// // This module implements a 2-bit down counter that decrements its value on each rising edge of the clock signal (CLK). When the active-high RESET signal is asserted (HIGH), the output (Q) is reset to zero (00). Otherwise, the counter continues to count downward, cycling through the values from 11 to 00.
module top_module(
    Q      ,
    CLK    ,
    RESET_B
);output reg [1:0] Q;
    input  CLK;
    input  RESET_B;

    always @(posedge CLK or negedge RESET_B) begin
        if (!RESET_B) begin
            Q <= 2'b00;
        end else begin
            Q <= Q + 1;
        end
    end

endmodule
